import heapq

def merge_sorted_list(*inputs):
    heap = []
    iterators = [iter(lst) for lst in inputs]
    for i, it in enumerate(iterators):
        try:
            first_val = next(it)
            heapq.heappush(heap, (first_val, i, it))
        except StopIteration:
            pass
    result = []
    while heap:
        val, idx, it = heapq.heappop(heap)
        result.append(val)
        try:
