def num_comm_div(a, b):
    def gcd(x, y):
        while y:
            x, y = y, x % y
        return x
    g = gcd(a, b)
    count = 0
    i = 1
    while i * i <= g:
        if g % i == 0:
            count += 1
            if i != g // i:
                count += 1
        i += 1
    return count
