def no_of_subsequences(arr, k):
    if k <= 1:
        return 0
    arr.sort()
    count = 0
    n = len(arr)
    for i in range(n):
        product = 1
        for j in range(i, n):
            product *= arr[j]
            if product < k:
                count += 1
            else:
                break
    return count
